const fs = require('fs');

const problemsPath = path.resolve(__dirname, '../../data/problems.json');

function loadProblems() {
	const data = fs.readFileSync(problemsPath, 'utf8');
	return JSON.parse(data);
}

/**
 * Get detailed problem info by problemId including aggregated component statistics.
 * @param {string} problemId
 * @returns {object} problem detail with component stats or null if not found
 */
function getProblemDetail(problemId) {
	const problems = loadProblems();
	const problem = problems.find(p => p.id === problemId);
	if (!problem) return null;

	// Aggregate component statistics
	const components = problem.components || [];

	const languageCounts = {};
	const statusCounts = {};
	let maxPoints = 0;

	components.forEach(component => {
		if (component.language) {
			languageCounts[component.language] = (languageCounts[component.language] || 0) + 1;
		}
		if (component.status) {
			statusCounts[component.status] = (statusCounts[component.status] || 0) + 1;
		}
		if (typeof component.points === 'number' && component.points > maxPoints) {
			maxPoints = component.points;
		}
	});

	return {
		id: problem.id,
		title: problem.title,
		description: problem.description,
		components: components,
		componentStats: {
			languageCounts,
			statusCounts,
			maxPoints
		}
	};
}

module.exports = {
	getProblemDetail
};
